gallery-sort	Gallery Sort / Auto-Sort	Gallery	locked	POST /admin/api/gallery/<slug>/sort — reorders gallery_json by type
pages-overlay	Edit Overlay Injection	Pages	stable	toggleEditOverlay() in pages.html — injects overlay-scripts into iframe
gallery-masonry	Masonry Layout Engine	Gallery	locked	preview/js/gallery.js — GalleryEngine.layoutAll, CSS grid masonry
pages-text	Text Editor	Pages	locked	Inline text editing via contenteditable + text-edits endpoint
gallery-delete	Gallery Delete Endpoint	Gallery	locked	POST /admin/api/gallery/<slug>/remove — removes image from gallery_json
gallery-lightbox	Lightbox	Gallery	locked	preview/js/lightbox.js — open/close/nav/keyboard/touch
pages-hero	Hero Image Editor	Pages	locked	_EDIT_OVERLAY_TPL — zoom/pan/upload hero image
frontend-css	main.css	Frontend	locked	preview/css/main.css — all site styles
frontend-main	main.js	Frontend	locked	preview/js/main.js — nav, mobile menu, global handlers
server-db	Database Connection Layer	Server	locked	_db_conn(), _DB_URL, connection hygiene
seo-schema	Schema Markup	SEO	locked	JSON-LD on all pages — LocalBusiness, BreadcrumbList
frontend-gallery	gallery.js	Frontend	locked	preview/js/gallery.js — do not modify without testing masonry
seo-service-pages	Service Pages HTML	SEO	locked	All service/location pages under preview/services/
seo-sitemap	Sitemap	SEO	locked	preview/sitemap.xml — 130 URLs, must stay current
server-render	Project Page Render Pipeline	Server	locked	_render_project_page(p) — generates HTML for all 18 project pages
seo-project-pages	Project Page HTML	SEO	locked	All 18 project pages — gallery, hero, schema markup
server-auth	Auth / Token System	Server	locked	_require_admin(), _valid_token(), admin_sessions table
server-rerender	AI Re-render (Gemini)	Server	locked	/admin/api/images/rerender — gemini-3.1-flash-image-preview
gallery-add	Gallery Add Image Endpoint	Gallery	locked	POST /admin/api/gallery/<slug>/add-image — upload and append to gallery
gallery-tag	Gallery Tag Endpoint	Gallery	locked	POST /admin/api/gallery/<slug>/tag — saves image_type to gallery_image_types
pages-undo	Undo System	Pages	locked	undo_log table, /admin/api/undo endpoint, _log_undo()
pages-card	Card Image Editor	Pages	locked	_CARD_EDIT_OVERLAY_TPL — setupCard(), type badge, delete, browse
server-routes	Static File Routes	Server	locked	/view/<path>, /assets/, /migrate_*.bat routes
