el","Where":"Castro Valley, CA","When":"2023"}	ff5b18_fa64df3266cb4f5687726c7ab5ac76f7_mv2	jpg	[["ff5b18_8534e71718a54408b57038ba0fc8c02f_mv2", "jpg"], ["ff5b18_60cc1d030a0345f9842e564e4f3dbeae_mv2", "jpg"], ["ff5b18_4b1779cf3392422587cb7f1388175437_mv2", "jpg"], ["ff5b18_5790c7262fb04a25a5f08dc6b385e4c9_mv2", "jpg"], ["ff5b18_da172978dd76485a9d179ca34d1c936b_mv2", "jpg"], ["ff5b18_1eda3d15c3f849579ab21c436e0ceb0d_mv2", "jpg"], ["ff5b18_fa64df3266cb4f5687726c7ab5ac76f7_mv2", "jpg"], ["ff5b18_d7eb886d364544c1993777e2db5e8bb6_mv2", "jpg"], ["ff5b18_92fd4a14ebbe454eadd6715a9ccf6053_mv2", "jpg"]]	f
