tion\\": \\"Luxury design-build firm specializing in custom homes and high-end remodels across Pleasanton, Danville, Walnut Creek, Lafayette, Orinda, Alamo, San Ramon and the East Bay.\\",\\n  \\"url\\": \\"https://www.ridgecrestdesigns.com\\",\\n  \\"telephone\\": \\"+19257842798\\",\\n  \\"email\\": \\"info@ridgecrestdesigns.com\\",\\n  \\"foundingDate\\": \\"2013\\",\\n  \\"founder\\": {\\"@type\\":\\"Person\\",\\"name\\":\\"Tyler Ridgecrest\\"},\\n  \\"priceRange\\": \\"$$$$$\\",\\n  \\"address\\": {\\"@type\\":\\"PostalAddress\\",\\"streetAddress\\":\\"5502 Sunol Blvd Suite 100\\",\\"addressLocality\\":\\"Pleasanton\\",\\"addressRegion\\":\\"CA\\",\\"postalCode\\":\\"94566\\",\\"addressCountry\\":\\"US\\"},\\n  \\"geo\\": {\\"@type\\":\\"GeoCoordinates\\",\\"latitude\\":37.6624,\\"longitude\\":-121.8747}\\n}\\n  </script>\\n  <script type=\\"application/ld+json\\">\\n  {\\n  \\"@context\\": \\"https://schema.org\\",\\n  \\"@type\\": \\"CreativeWork\\",\\n  \\"name\\": \\"Danville Dream Home\\",\\n  \\"description\\": \\"Ridgecrest Designs transformed this Danville dream home into a stunning showcase of luxury design, craftsmanship, and custom detail — where every finish was chosen with precision and every space tells a story.\\",\\n  \\"url\\": \\"https://www.ridgecrestdesigns.com/danville-dream\\",\\n  \\"creator\\": {\\"@type\\":\\"Organization\\",\\"name\\":\\"Ridgecrest Designs\\"},\\n  \\"locationCreated\\": {\\"@type\\":\\"Place\\",\\"address\\":{\\"@type\\":\\"PostalAddress\\",\\"addressLocality\\":\\"Danville\\",\\"addressRegion\\":\\"CA\\",\\"addressCountry\\":\\"US\\"}}\\n}\\n  </script>\\n</head>\\n<body>\\n\\n  <nav class=\\"nav nav--scrolled\\" id=\\"nav\\">\\n    <a href=\\"index.html\\" class=\\"nav__logo\\">RIDGECREST DESIGNS</a>\\n    <button class=\\"nav__toggle\\" id=\\"navToggle\\" aria-label=\\"Menu\\">\\n      <span></span><span></span><span></span>\\n    </button>\\n    <ul class=\\"nav__links\\" id=\\"navLinks\\">\\n      <li><a href=\\"about.html\\">About</a></li>\\n      <li><a href=\\"process.html\\">Process</a></li>\\n      <li><a href=\\"services.html\\">Services</a></li>\\n      <li><a href=\\"portfolio.html\\">Portfolio</a></li>\\n      <li><a href=\\"/blog\\">The RD Edit</a></li>\\n      <li><a href=\\"team.html\\">Team</a></li>\\n      <li><a href=\\"contact.html\\" class=\\"nav__cta\\">Start a Project</a></li>\\n    </ul>\\n  </nav>\\n\\n  <div class=\\"project-hero\\">\\n    <div class=\\"project-hero__img\\" role=\\"img\\" aria-label=\\"Danville Dream Home by Ridgecrest Designs, Danville, CA\\" style=\\"background-image:url('/assets/images-opt/ff5b18_83cbc49d23a5436294574e1dd9db3819_mv2.webp')\\"></div>\\n    <div class=\\"project-hero__overlay\\"></div>\\n  </div>\\n\\n  <section class=\\"project-meta section\\" style=\\"padding-bottom:0\\">\\n    <div class=\\"container\\">\\n      <p class=\\"breadcrumb-back\\"><a href=\\"portfolio.html\\">← Portfolio</a></p>\\n      <div class=\\"project-meta__inner\\">\\n        <div>\\n          <p class=\\"section__label\\">Danville, CA</p>\\n          <h1 class=\\"project-meta__title\\">Danville Dream Home</h1>\\n          <div class=\\"project-meta__tags\\">\\n            <span class=\\"project-meta__tag\\">Luxury Home Remodel</span>\\n            <span class=\\"project-meta__tag\\">2024</span>\\n          </div>\\n        </div>\\n        <div class=\\"project-meta__cta\\">\\n          <a href=\\"https://elevate-scheduling-6b2fdec8.base44.app/ProjectInquiryForm\\" class=\\"btn btn--dark\\">Start a Similar Project</a>\\n        </div>\\n      </div>\\n      <div class=\\"project-description\\">\\n        <p>Ridgecrest Designs transformed this Danville dream home into a stunning showcase of luxury design, craftsmanship, and custom detail. This whole-home remodel required deep coordination across design, engineering, and construction — hallmarks of the Ridgecrest design-build approach.</p>\\n        <p>Every room was thoughtfully reimagined with high-end finishes, custom millwork, and bespoke fixtures sourced to exact specification. The result is a home that feels entirely tailored — not assembled — because it was built with the same care Ridgecrest brings to every project, from first render to final walkthrough.</p>\\n        <p>The clients came with a vision. Ridgecrest made it precise, then built it flawlessly.</p>\\n        \\n      </div>\\n      <div class=\\"project-specs\\"><div class=\\"project-spec\\"><span class=\\"project-spec__label\\">What</span><span class=\\"project-spec__val\\">Luxury Home Remodel</span></div><div class=\\"project-spec\\"><span class=\\"project-spec__label\\">Where</span><span class=\\"project-spec__val\\">Danville, CA</span></div><div class=\\"project-spec\\"><span class=\\"project-spec__label\\">When</span><span class=\\"project-spec__val\\">2024</span></div></div>\\n    </div>\\n  </section>\\n\\n  <section class=\\"project-gallery\\">\\n    <div class=\\"container\\">\\n      <p class=\\"project-gallery__label\\">Project Gallery</p>\\n      <div class=\\"gallery-masonry\\">\\n      <div class=\\"gallery-item\\" data-card-id=\\"danville-dream-gal-ff5b18_aac54aec732d47c7b4d53e34ae6aa5ff_mv2\\" data-src=\\"/assets/images-opt/ff5b18_aac54aec732d47c7b4d53e34ae6aa5ff_mv2.webp\\" data-image-type=\\"project\\" data-gallery-hash=\\"ff5b18_aac54aec732d47c7b4d53e34ae6aa5ff_mv2\\">\\n        <img src=\\"/assets/images-opt/ff5b18_aac54aec732d47c7b4d53e34ae6aa5ff_mv2.webp\\" width=\\"1080\\" height=\\"686\\" alt=\\"Danville Dream Home — photo 1\\" loading=\\"lazy\\" />\\n        <div class=\\"gallery-item__overlay\\"><span class=\\"gallery-item__zoom\\">+</span></div>\\n      </div>\\n      <div class=\\"gallery-item\\" data-card-id=\\"danville-dream-gal-ff5b18_3c0cef18e48849089c5ed48614041900_mv2\\" data-src=\\"/assets/images-opt/ff5b18_3c0cef18e48849089c5ed48614041900_mv2.webp\\" data-image-type=\\"project\\" data-gallery-hash=\\"ff5b18_3c0cef18e48849089c5ed48614041900_mv2\\">\\n  