Danville\\"},\\n      {\\"@type\\": \\"City\\", \\"name\\": \\"Lafayette\\"},\\n      {\\"@type\\": \\"City\\", \\"name\\": \\"Orinda\\"},\\n      {\\"@type\\": \\"City\\", \\"name\\": \\"Alamo\\"},\\n      {\\"@type\\": \\"City\\", \\"name\\": \\"Walnut Creek\\"},\\n      {\\"@type\\": \\"City\\", \\"name\\": \\"San Ramon\\"},\\n      {\\"@type\\": \\"City\\", \\"name\\": \\"Moraga\\"},\\n      {\\"@type\\": \\"City\\", \\"name\\": \\"Sunol\\"}\\n    ],\\n    \\"sameAs\\": [\\n      \\"https://www.facebook.com/ridgecrestdesigns\\",\\n      \\"https://www.instagram.com/ridgecrestdesigns\\",\\n      \\"https://www.houzz.com/pro/ridgecrestdesigns\\"\\n    ]\\n  }\\n  </script>\\n  <script type=\\"application/ld+json\\">\\n  {\\n    \\"@context\\": \\"https://schema.org\\",\\n    \\"@type\\": \\"Service\\",\\n    \\"name\\": \\"Luxury Kitchen Remodel\\",\\n    \\"provider\\": { \\"@type\\": \\"Organization\\", \\"name\\": \\"Ridgecrest Designs\\" },\\n    \\"description\\": \\"High-specification kitchen renovations starting at $150,000. Custom cabinetry, stonework, premium appliances — designed and built to last decades.\\",\\n    \\"areaServed\\": \\"East Bay, California\\",\\n    \\"url\\": \\"https://www.ridgecrestdesigns.com/kitchen-remodels\\",\\n    \\"breadcrumb\\": {\\n      \\"@type\\": \\"BreadcrumbList\\",\\n      \\"itemListElement\\": [\\n        {\\"@type\\": \\"ListItem\\", \\"position\\": 1, \\"name\\": \\"Home\\", \\"item\\": \\"https://www.ridgecrestdesigns.com\\"},\\n        {\\"@type\\": \\"ListItem\\", \\"position\\": 2, \\"name\\": \\"Services\\", \\"item\\": \\"https://www.ridgecrestdesigns.com/services\\"},\\n        {\\"@type\\": \\"ListItem\\", \\"position\\": 3, \\"name\\": \\"Kitchen Remodels\\", \\"item\\": \\"https://www.ridgecrestdesigns.com/kitchen-remodels\\"}\\n      ]\\n    }\\n  }\\n  </script>\\n  <!-- ─────────────────────────────────────────────────────── -->\\n</head>\\n<body>\\n\\n  <nav class=\\"nav nav--scrolled\\" id=\\"nav\\">\\n    <a href=\\"index.html\\" class=\\"nav__logo\\">RIDGECREST DESIGNS</a>\\n    <button class=\\"nav__toggle\\" id=\\"navToggle\\" aria-label=\\"Menu\\">\\n      <span></span><span></span><span></span>\\n    </button>\\n    <ul class=\\"nav__links\\" id=\\"navLinks\\">\\n      <li><a href=\\"about.html\\">About</a></li>\\n      <li><a href=\\"process.html\\">Process</a></li>\\n      <li><a href=\\"services.html\\">Services</a></li>\\n      <li><a href=\\"portfolio.html\\">Portfolio</a></li>\\n      <li><a href=\\"/blog\\">The RD Edit</a></li>\\n      <li><a href=\\"team.html\\">Team</a></li>\\n      <li><a href=\\"contact.html\\" class=\\"nav__cta\\">Start a Project</a></li>\\n    </ul>\\n  </nav>\\n\\n  <!-- HERO -->\\n  <div class=\\"page-hero page-hero--service\\" style=\\"background-image:url('/assets/images-opt/ff5b18_d7eb886d364544c1993777e2db5e8bb6_mv2.webp')\\">\\n    <p class=\\"page-hero__eyebrow\\">Kitchen Remodels · East Bay, California</p>\\n    <h1 class=\\"page-hero__title\\">The kitchen your home<br><em>was always meant to have.</em></h1>\\n    <p class=\\"page-hero__sub\\">Luxury kitchen renovations starting at $150,000. Custom cabinetry, premium stonework, professional appliances — designed in detail before a single cabinet is pulled.</p>\\n    <div class=\\"page-hero__actions\\">\\n      <a href=\\"https://elevate-scheduling-6b2fdec8.base44.app/ProjectInquiryForm\\" class=\\"btn btn--primary btn--lg\\">Start Your Project Inquiry</a>\\n    </div>\\n  </div>\\n\\n  <!-- WHAT TO EXPECT -->\\n  <section class=\\"section section--accent\\">\\n    <div class=\\"container\\">\\n      <div class=\\"section__header\\">\\n        <p class=\\"section__label\\">What to Expect</p>\\n        <h2 class=\\"section__headline\\">A kitchen built around<br><em>how you actually live</em></h2>\\n      </div>\\n      <div class=\\"about-values\\">\\n        <div class=\\"value-card\\">\\n          <div class=\\"value-card__icon\\">◇</div>\\n          <div class=\\"value-card__title\\">What We Bring</div>\\n          <div class=\\"value-card__desc\\">Deep expertise in kitchen design, custom cabinetry, stone and tile specification, appliance integration, and the MEP coordination that a high-specification kitchen demands. We've built kitchens for homeowners who cook seriously, entertain lavishly, and won't compromise on either.</div>\\n        </div>\\n        <div class=\\"value-card\\">\\n          <div class=\\"value-card__icon\\">◇</div>\\n          <div class=\\"value-card__title\\">What the Process Looks Like</div>\\n          <div class=\\"value-card__desc\\">We start with how you use your kitchen — then design from there. Custom cabinet layouts, stone slab selections, appliance specifications, lighting design, and plumbing layout are all developed before any demolition begins. You'll see the finished kitchen in photo-realistic detail first.</div>\\n        </div>\\n        <div class=\\"value-card\\">\\n          <div class=\\"value-card__icon\\">◇</div>\\n          <div class=\\"value-card__title\\">What You Receive</div>\\n          <div class=\\"value-card__desc\\">A kitchen that functions as the center of your home — custom built-ins, precision stonework, professional-grade appliances, and finish carpentry that will outlast trends. Built by specialists, not generalists, and delivered without the change-order chaos common to lesser projects.</div>\\n        </div>\\n      </div>\\n    </div>\\n  </section>\\n\\n  <!-- GALLERY -->\\n  <section class=\\"section\\" style=\\"padding-top:0; padding-bottom:0;\\">\\n    <div class=\\"gallery-grid\\" style=\\"display:grid; grid-template-columns:repeat(2,1fr); gap:3px;\\">\\n      <div class=\\"gallery-item\\" data-src=\\"/assets/images-opt/ff5b18_94919d08fc9245fc849ac03c4ea2caaf_mv2.webp\\">\\n        <div data-card-id=\\"kitchen-remodels-gallery-1\\" class=\\"gallery-item__img\\" role=\\"img\\" aria-label=\\"Orinda Kitchen — luxury kitchen remodel by Ridgecrest Designs\\" style=\\"background-image:url('/assets/images-opt/ff5b18_94919d08fc9245fc849ac03c4ea2caaf_mv2.webp'); height:420px; background-size:cover; background-position:center;\\"></div>\\n        <div class=\\"gallery-item__overlay\\"><span class=\\"gallery-item__zoom\\">+</span></div>\\n      </div>\\n      <div class=\\"gallery-item\\" data-src=\\"/assets/images-opt/ff5b18_598ba1466dbb45249778e2ea0e0b95e3_mv2.webp\\">\\n        <div data-card-id=\\"kitchen-remodels-gallery-2\\" class=\\"gallery-item__img\\" role=\\"img\\" aria-label=\\"Danville navy kitchen — luxury kitchen remodel by Ridgecrest Designs\\" style=\\"background-image:url('/assets/images-opt/ff5b18_598ba1466dbb45249778e2ea0e0b95e3_mv2.webp'); height:420px; background-size:cover; background-position:center;\\"></div>\\n        <div class=\\"gallery-item__overlay\\"><span class=\\"gallery-item__zoom\\">+</span></div>\\n      </div>\\n      <div class=\\"gallery-item\\" data-src=\\"/assets/images-opt/ff5b18_086efaaaac9f44f9bfebafc043e1a7a2_mv2.webp\\">\\n        <div data-card-id=\\"kitchen-remodels-gallery-3\\" class=\\"gallery-item__img\\" role=\\"img\\" aria-label=\\"Farmhouse kitchen — luxury kitchen remodel by Ridgecrest Designs\\" style=\\"background-image:url('/assets/images-opt/ff5b18_086efaaaac9f44f9bfebafc043e1a7a2_mv2.webp'); height:420px; background-size:cover; background-position:center;\\"></div>\\n        <div class=\\"gallery-item__overlay\\"><span class=\\"gallery-item__zoom\\">+</span></div>\\n      </div>\\n      <div class=\\"gallery-item\\" data-src=\\"/assets/images-opt/ff5b18_eba842cf7eb641b58bd420804e76cb50_mv2.webp\\">\\n        <div data-card-id=\\"kitchen-remodels-gallery-4\\" class=\\"gallery-item__img\\" role=\\"img\\" aria-label=\\"Mountain retreat kitchen — luxury kitchen remodel by Ridgecrest Designs\\" style=\\"background-image:url('/assets/images-opt/ff5b18_eba842cf7eb641b58bd420804e76cb50_mv2.webp'); height:420px; background-size:cover; background-position:center;\\"></div>\\n        <div class=\\"gallery-item__overlay\\"><span class=\\"gallery-item__zoom\\">+</span></div>\\n      </div>\\n    </div>\\n  </section>\\n\\n  <div class=\\"lightbox\\" id=\\"lightbox\\">\\n    <span class=\\"lightbox__close\\">&times;</span>\\n    <span class=\\"lightbox__prev\\">&#8592;</span>\\n    <img class=\\"lightbox__img\\" src=\\"\\" alt=\\"Project photo\\" />\\n    <span class=\\"lightbox__next\\">&#8594;</span>\\n    <span class=\\"lightbox__counter\\"></span>\\n  </div>\\n\\n  <!-- PROCESS STEPS -->\\n  <section class=\\"section\\">\\n    <div class=\\"container\\">\\n      <div class=\\"section__header\\">\\n        <p class=\\"section__label\\">Our Process</p>\\n        <h2 class=\\"section__headline\\">Designed before demolition.<br><em>Built without compromise.</em></h2>\\n      </div>\\n      <div class=\\"process-steps\\">\\n        <div class=\\"process-step\\">\\n          <div class=\\"process-step__num\\">1</div>\\n          <div class=\\"process-step__content\\">\\n            <div class=\\"process-step__title\\">Design</div>\\n            <h3 class=\\"process-step__headline\\">Custom layout built around your kitchen life</h3>\\n            <p class=\\"process-step__body\\">We begin by understanding how your household uses the kitchen — cooking patterns, entertaining style, storage requirements, appliance preferences. From there, our design team develops a custom cabinet layout, island configuration, material palette, and appliance specification tailored to how you actually live, not a template.</p>\\n          </div>\\n        </div>\\n        <div class=\\"process-step\\">\\n          <div class=\\"process-step__num\\">2</div>\\n          <div class=\\"process-step__content\\">\\n            <div class=\\"process-step__title\\">Render</div>\\n            <h3 class=\\"process-step__headline\\">See every finish before we order a single cabinet</h3>\\n            <p class=\\"process-step__body\\">Photo-realistic 3D renders show your kitchen exactly as it will look — stone slab veining, cabinet door profiles, hardware finishes, lighting fixtures, flooring, and all. You'll make every material decision with full visual context, not swatches and imagination. Revisions happen in the render, not in the field.</p>\\n          </div>\\n        </div>\\n        <div class=\\"process-step\\">\\n          <div class=\\"process-step__num\\">3</div>\\n          <div class=\\"process-step__content\\">\\n            <div class=\\"process-step__title\\">Permit</div>\\n            <h3 class=\\"process-step__headline\\">Plumbing, electrical, and structural handled</h3>\\n            <p class=\\"process-step__body\\">High-specification kitchens often involve plumbing relocations, electrical panel upgrades, and structural modifications. Our team prepares all permit documentation, coordinates with local inspectors, and manages the approval timeline so construction starts on schedule — not after months of back-and-forth.</p>\\n          </div>\\n        </div>\\n        <div class=\\"process-step\\">\\n          <div class=\\"process-step__num\\">4</div>\\n          <div class=\\"process-step__content\\">\\n            <div class=\\"process-step__title\\">Build</div>\\n            <h3 class=\\"process-step__headline\\">Specialists in cabinetry, stone, and finish work</h3>\\n            <p class=\\"process-step__body\\">Custom cabinet installation, stone fabrication and templating, tile setting, and appliance integration are performed by trade specialists who work exclusively on high-specification projects. Your project manager coordinates every phase, ensures quality at each milestone, and delivers a kitchen that performs as precisely as it looks.</p>\\n          </div>\\n        </div>\\n      </div>\\n    </div>\\n  </section>\\n\\n  <!-- INVESTMENT -->\\n  <section class=\\"section section--dark\\">\\n    <div class=\\"container\\">\\n      <div class=\\"diff__layout\\">\\n        <div class=\\"diff__visual\\">\\n          <div class=\\"diff__visual-inner\\">\\n            <div class=\\"diff__quote\\">&ldquo;See it before we build it.&rdquo;</div>\\n            <div class=\\"diff__stats\\">\\n              <div class=\\"diff__stat\\">\\n                <span class=\\"diff__num\\">$150K+</span>\\n                <span class=\\"diff__lbl\\">Starting Investment</span>\\n              </div>\\n              <div class=\\"diff__stat\\">\\n                <span class=\\"diff__num\\">12+</span>\\n                <span class=\\"diff__lbl\\">Years of Luxury Kitchen Work</span>\\n              </div>\\n            </div>\\n          </div>\\n        </div>\\n        <div class=\\"diff__content\\">\\n          <p class=\\"section__label\\">Investment</p>\\n          <h2 class=\\"section__headline\\">Kitchen remodels<br><em>starting at $150,000</em></h2>\\n          <p class=\\"diff__body\\">A Ridgecrest kitchen is custom-designed, premium-specified, and built to last decades. Our projects start at $150,000 and reflect the quality of cabinetry, stonework, appliances, and craftsmanship involved. We are the right firm for homeowners who want a kitchen that performs and looks extraordinary — not a cosmetic update.</p>\\n          <ul class=\\"diff__list\\">\\n            <li>\\n              <div class=\\"diff__icon\\">→</div>\\n              <div>\\n                <strong>Custom Cabinetry &amp; Millwork</strong>\\n                <span>Built to your exact specifications, not stock dimensions.</span>\\n              </div>\\n            </li>\\n            <li>\\n              <div class=\\"diff__icon\\">→</div>\\n              <div>\\n                <strong>Natural Stone &amp; Premium Materials</strong>\\n                <span>Full slab selection with templating and precision fabrication.</span>\\n              </div>\\n            </li>\\n            <li>\\n              <div class=\\"diff__icon\\">→</div>\\n              <div>\\n                <strong>Professional Appliance Integration</strong>\\n                <span>Sub-Zero, Wolf, Miele, and other pro-grade specifications.</span>\\n              </div>\\n            </li>\\n            <li>\\n              <div class=\\"diff__icon\\">→</div>\\n              <div>\\n                <strong>Photo-Realistic Renders Included</strong>\\n                <span>Every finish decision made with visual certainty.</span>\\n              </div>\\n            </li>\\n          </ul>\\n          <a href=\\"https://elevate-scheduling-6b2fdec8.base44.app/ProjectInquiryForm\\" class=\\"btn btn--primary\\" style=\\"margin-top:1.5rem\\">Submit a Project Inquiry</a>\\n          <p style=\\"color:rgba(255,255,255,0.4); font-size:0.8rem; margin-top:0.8rem;\\">Or call <a href=\\"tel:9257842798\\" style=\\"color:rgba(255,255,255,0.6);\\">925-784-2798</a></p>\\n        </div>\\n      </div>\\n    </div>\\n  </section>\\n\\n  <!-- CTA -->\\n  <section class=\\"cta section section--dark\\" style=\\"padding-top:0\\">\\n    <div class=\\"container container--narrow cta__inner\\">\\n      <h2 class=\\"cta__headline\\">Your kitchen should be<br><em>worth walking into.</em></h2>\\n      <p class=\\"cta__sub\\">Tell us about your project. We'll tell you exactly what we can build for you.</p>\\n      <a href=\\"https://elevate-scheduling-6b2fdec8.base44.app/ProjectInquiryForm\\" class=\\"btn btn--primary btn--lg\\">Submit a Project Inquiry</a>\\n      <p class=\\"cta__note\\">Or call <a href=\\"tel:9257842798\\">925-784-2798</a></p>\\n    </div>\\n  </section>\\n\\n  <footer class=\\"footer\\">\\n    <div class=\\"container footer__inner\\">\\n      <div class=\\"footer__brand\\">\\n        <span class=\\"footer__logo\\">RIDGECREST DESIGNS</span>\\n        <p class=\\"footer__tagline\\">Luxury Design-Build &middot; Est. 2013</p>\\n        <p class=\\"footer__tagline\\" style=\\"font-style:italic; opacity:0.6\\">Experience the Ridgecrest difference.</p>\\n        <p class=\\"footer__address\\">5502 Sunol Blvd, Suite 100<br>Pleasanton, CA 94566</p>\\n        <p><a href=\\"tel:9257842798\\">925-784-2798</a> &middot; <a href=\\"mailto:info@ridgecrestdesigns.com\\">info@ridgecrestdesigns.com</a></p>\\n      </div>\\n      <div class=\\"footer__nav\\">\\n        <div class=\\"footer__col\\">\\n          <p class=\\"footer__col-head\\">Company</p>\\n          <a href=\\"about.html\\">About</a>\\n          <a href=\\"team.html\\">Team</a>\\n          <a href=\\"process.html\\">Process</a>\\n          <a href=\\"portfolio.html\\">Portfolio</a>\\n        </div>\\n        <div class=\\"footer__col\\">\\n          <p class=\\"footer__col-head\\">Services</p>\\n          <a href=\\"custom-homes.html\\">Custom Homes</a>\\n          <a href=\\"whole-house-remodels.html\\">Whole House Remodels</a>\\n          <a href=\\"kitchen-remodels.html\\">Kitchen Remodels</a>\\n          <a href=\\"bathroom-remodels.html\\">Bathroom Remodels</a>\\n        </div>\\n                <div class=\\"footer__col\\">\\n          <p class=\\"footer__col-head\\">Service Areas</p>\\n          <a href=\\"services/alamo.html\\">Alamo</a>\\n          <a href=\\"services/danville.html\\">Danville</a>\\n          <a href=\\"services/diablo.html\\">Diablo</a>\\n          <a href=\\"services/dublin.html\\">Dublin</a>\\n          <a href=\\"services/lafayette.html\\">Lafayette</a>\\n          <a href=\\"services/moraga.html\\">Moraga</a>\\n          <a href=\\"services/orinda.html\\">Orinda</a>\\n          <a href=\\"services/pleasanton.html\\">Pleasanton</a>\\n          <a href=\\"services/rossmoor.html\\">Rossmoor</a>\\n          <a href=\\"services/san-ramon.html\\">San Ramon</a>\\n          <a href=\\"services/sunol.html\\">Sunol</a>\\n          <a href=\\"services/walnut-creek.html\\">Walnut Creek</a>\\n        </div>\\n        <div class=\\"footer__col\\">\\n          <p class=\\"footer__col-head\\">Connect</p>\\n          <a href=\\"https://elevate-scheduling-6b2fdec8.base44.app/ProjectInquiryForm\\">Start a Project</a>\\n         