og:image\\" content=\\"/assets/images/ff5b18_3c0cef18e48849089c5ed48614041900_mv2.png\\" />\\n  <meta name=\\"twitter:card\\" content=\\"summary_large_image\\" />\\n  <meta name=\\"twitter:title\\" content=\\"About — Ridgecrest Designs | Luxury Design-Build, Pleasanton CA\\" />\\n  <meta name=\\"twitter:description\\" content=\\"Ridgecrest Designs was founded in 2013 in Pleasanton, CA. A full-service luxury design-build firm specializing in custom homes and high-end remodels across the Tri-Valley and East Bay.\\" />\\n  <meta name=\\"twitter:image\\" content=\\"/assets/images/ff5b18_3c0cef18e48849089c5ed48614041900_mv2.png\\" />\\n  <script type=\\"application/ld+json\\">\\n  {\\n  \\"@context\\": \\"https://schema.org\\",\\n  \\"@type\\": [\\n    \\"LocalBusiness\\",\\n    \\"HomeAndConstructionBusiness\\"\\n  ],\\n  \\"name\\": \\"Ridgecrest Designs\\",\\n  \\"description\\": \\"Luxury design-build firm specializing in custom homes and high-end remodels across Pleasanton, Danville, Walnut Creek, Lafayette, Orinda, Alamo, San Ramon and the East Bay.\\",\\n  \\"url\\": \\"https://www.ridgecrestdesigns.com\\",\\n  \\"telephone\\": \\"+19257842798\\",\\n  \\"email\\": \\"info@ridgecrestdesigns.com\\",\\n  \\"foundingDate\\": \\"2013\\",\\n  \\"founder\\": {\\n    \\"@type\\": \\"Person\\",\\n    \\"name\\": \\"Tyler Ridgecrest\\"\\n  },\\n  \\"priceRange\\": \\"$$$$$\\",\\n  \\"address\\": {\\n    \\"@type\\": \\"PostalAddress\\",\\n    \\"streetAddress\\": \\"5502 Sunol Blvd Suite 100\\",\\n    \\"addressLocality\\": \\"Pleasanton\\",\\n    \\"addressRegion\\": \\"CA\\",\\n    \\"postalCode\\": \\"94566\\",\\n    \\"addressCountry\\": \\"US\\"\\n  },\\n  \\"geo\\": {\\n    \\"@type\\": \\"GeoCoordinates\\",\\n    \\"latitude\\": 37.6624,\\n    \\"longitude\\": -121.8747\\n  },\\n  \\"areaServed\\": [\\n    {\\n      \\"@type\\": \\"City\\",\\n      \\"name\\": \\"Pleasanton\\"\\n    },\\n    {\\n      \\"@type\\": \\"City\\",\\n      \\"name\\": \\"Danville\\"\\n    },\\n    {\\n      \\"@type\\": \\"City\\",\\n      \\"name\\": \\"Walnut Creek\\"\\n    },\\n    {\\n      \\"@type\\": \\"City\\",\\n      \\"name\\": \\"Lafayette\\"\\n    },\\n    {\\n      \\"@type\\": \\"City\\",\\n      \\"name\\": \\"Orinda\\"\\n    },\\n    {\\n      \\"@type\\": \\"City\\",\\n      \\"name\\": \\"Alamo\\"\\n    },\\n    {\\n      \\"@type\\": \\"City\\",\\n      \\"name\\": \\"San Ramon\\"\\n    },\\n    {\\n      \\"@type\\": \\"City\\",\\n      \\"name\\": \\"Dublin\\"\\n    },\\n    {\\n      \\"@type\\": \\"City\\",\\n      \\"name\\": \\"Moraga\\"\\n    },\\n    {\\n      \\"@type\\": \\"City\\",\\n      \\"name\\": \\"Sunol\\"\\n    }\\n  ],\\n  \\"sameAs\\": [\\n    \\"https://www.facebook.com/ridgecrestdesigns\\",\\n    \\"https://www.instagram.com/ridgecrestdesigns\\",\\n    \\"https://www.houzz.com/pro/ridgecrestdesigns\\"\\n  ]\\n}\\n  </script>\\n  <script type=\\"application/ld+json\\">\\n  {\\n  \\"@context\\": \\"https://schema.org\\",\\n  \\"@type\\": \\"AboutPage\\",\\n  \\"name\\": \\"About Ridgecrest Designs\\",\\n  \\"url\\": \\"https://www.ridgecrestdesigns.com/about\\",\\n  \\"breadcrumb\\": {\\n    \\"@type\\": \\"BreadcrumbList\\",\\n    \\"itemListElement\\": [\\n      {\\n        \\"@type\\": \\"ListItem\\",\\n        \\"position\\": 1,\\n        \\"name\\": \\"Home\\",\\n        \\"item\\": \\"https://www.ridgecrestdesigns.com\\"\\n      },\\n      {\\n        \\"@type\\": \\"ListItem\\",\\n        \\"position\\": 2,\\n        \\"name\\": \\"About\\",\\n        \\"item\\": \\"https://www.ridgecrestdesigns.com/about\\"\\n      }\\n    ]\\n  }\\n}\\n  </script>\\n  <!-- ─────────────────────────────────────────────────────── -->\\n</head>\\n<body>\\n\\n  <nav class=\\"nav nav--scrolled\\" id=\\"nav\\">\\n    <a href=\\"index.html\\" class=\\"nav__logo\\">RIDGECREST DESIGNS</a>\\n    <button class=\\"nav__toggle\\" id=\\"navToggle\\" aria-label=\\"Menu\\">\\n      <span></span><span></span><span></span>\\n    </button>\\n    <ul class=\\"nav__links\\" id=\\"navLinks\\">\\n      <li><a href=\\"about.html\\">About</a></li>\\n      <li><a href=\\"process.html\\">Process</a></li>\\n      <li><a href=\\"services.html\\">Services</a></li>\\n      <li><a href=\\"portfolio.html\\">Portfolio</a></li>\\n      <li><a href=\\"/blog\\">The RD Edit</a></li>\\n      <li><a href=\\"team.html\\">Team</a></li>\\n      <li><a href=\\"contact.html\\" class=\\"nav__cta\\">Start a Project</a></li>\\n    </ul>\\n  </nav>\\n\\n  <div class=\\"page-hero page-hero--service\\">\\n    <p class=\\"page-hero__eyebrow\\">Our Story</p>\\n    <h1 class=\\"page-hero__title\\">Built on precision.<br><em>Defined by trust.</em></h1>\\n    <p class=\\"page-hero__sub\\">A design-build firm founded in 2013 with a singular focus: delivering extraordinary homes with zero compromise.</p>\\n  </div>\\n\\n  <section class=\\"section\\">\\n    <div class=\\"container\\">\\n      <div class=\\"about-split\\">\\n        <div class=\\"about-visual\\">\\n          <div class=\\"about-visual__text\\">\\n            <p class=\\"about-visual__quote\\">&ldquo;The render is the promise. The build is the proof.&rdquo;</p>\\n          </div>\\n        </div>\\n        <div class=\\"about-content\\">\\n          <p class=\\"section__label\\">Who We Are</p>\\n          <h2 class=\\"section__headline\\" style=\\"margin-bottom:1.5rem\\">Ridgecrest Designs</h2>\\n          <p>Founded in 2013 by Tyler Ridgecrest, Ridgecrest Designs is a full-service luxury design-build firm based in Pleasanton, California. We specialize in custom homes, luxury remodels, and architectural design across the Tri-Valley and East Bay.</p>\\n          <p>We are not a general contractor that subcontracts design, nor a design firm that hands off construction. We are a true design-build company — one team, one contract, one point of accountability — from the first sketch to the final walkthrough.</p>\\n          <p>Our approach starts with <strong>photo-realistic 3D renders</strong>. Before a single permit is filed, you'll see your home in precise, photographic detail. We believe visual certainty before construction begins is not a luxury — it's the standard.</p>\\n          <p>We serve the East Bay's most discerning homeowners: Pleasanton, Walnut Creek, Danville, Lafayette, Orinda, Alamo, and the surrounding communities.</p>\\n          <a href=\\"contact.html\\" class=\\"btn btn--dark\\" style=\\"margin-top:1rem\\">Start a Conversation</a>\\n        </div>\\n      </div>\\n    </div>\\n  </section>\\n\\n  <section class=\\"section section--dark\\">\\n    <div class=\\"container\\">\\n      <div class=\\"section__header\\">\\n        <p class=\\"section__label\\">What Drives Us</p>\\n        <h2 class=\\"section__headline\\">Our core commitments</h2>\\n      </div>\\n      <div class=\\"about-values\\" style=\\"background:rgba(255,255,255,0.06); border-color:rgba(255,255,255,0.08);\\">\\n        <div class=\\"value-card\\" style=\\"background:#242424; color:var(--off-white)\\">\\n          <div class=\\"value-card__icon\\">◇</div>\\n          <div class=\\"value-card__title\\" style=\\"color:var(--off-white)\\">Precision</div>\\n          <div class=\\"value-card__desc\\" style=\\"color:rgba(255,255,255,0.5)\\">Every detail matters. We hold tolerances in design and construction that eliminate surprises and produce results that hold up over decades.</div>\\n        </div>\\n        <div class=\\"value-card\\" style=\\"background:#242424; color:var(--off-white)\\">\\n          <div class=\\"value-card__icon\\">◇</div>\\n          <div class=\\"value-card__title\\" style=\\"color:var(--off-white)\\">Integration</div>\\n          <div class=\\"value-card__desc\\" style=\\"color:rgba(255,255,255,0.5)\\">Design, engineering, permitting, and construction are not separate functions at Ridgecrest. They are one continuous process managed by one team.</div>\\n        </div>\\n        <div class=\\"value-card\\" style=\\"background:#242424; color:var(--off-white)\\">\\n          <div class=\\"value-card__icon\\">◇</div>\\n          <div class=\\"value-card__title\\" style=\\"color:var(--off-white)\\">Trust</div>\\n          <div class=\\"value-card__desc\\" style=\\"color:rgba(255,255,255,0.5)\\">We earn trust through transparency. Clear timelines, honest budgets, and regular communication are built into our process — not offered as extras.</div>\\n        </div>\\n        <div class=\\"value-card\\" style=\\"background:#242424; color:var(--off-white)\\">\\n          <div class=\\"value-card__icon\\">◇</div>\\n          <div class=\\"value-card__title\\" style=\\"color:var(--off-white)\\">Craftsmanship</div>\\n          <div class=\\"value-card__desc\\" style=\\"color:rgba(255,255,255,0.5)\\">We work with specialized teams whose work is measured not just by what looks good on delivery day, but by how it performs over years of living.</div>\\n        </div>\\n        <div class=\\"value-card\\" style=\\"background:#242424; color:var(--off-white)\\">\\n          <div class=\\"value-card__icon\\">◇</div>\\n          <div class=\\"value-card__title\\" style=\\"color:var(--off-white)\\">Process</div>\\n          <div class=\\"value-card__desc\\" style=\\"color:rgba(255,255,255,0.5)\\">Our five-stage process eliminates ambiguity. You know what happens next at every step — and why. No surprises, no scope creep, no confusion.</div>\\n        </div>\\n        <div class=\\"value-card\\" style=\\"background:#242424; color:var(--off-white)\\">\\n          <div class=\\"value-card__icon\\">◇</div>\\n          <div class=\\"value-card__title\\" style=\\"color:var(--off-white)\\">Excellence</div>\\n          <div class=\\"value-card__desc\\" style=\\"color:rgba(255,255,255,0.5)\\">We take on fewer projects than most firms our size — intentionally. It allows us to give each one the focused attention it deserves.</div>\\n        </div>\\n      </div>\\n    </div>\\n  </section>\\n\\n  <section class=\\"cta section section--dark\\" style=\\"padding-top:0\\">\\n    <div class=\\"container container--narrow cta__inner\\">\\n      <h2 class=\\"cta__headline\\">Let's talk about<br><em>your project.</em></h2>\\n      <p class=\\"cta__sub\\">We work best with homeowners who know what they want and appreciate a firm that delivers it without compromise.</p>\\n      <a href=\\"https://elevate-scheduling-6b2fdec8.base44.app/ProjectInquiryForm\\" class=\\"btn btn--primary btn--lg\\">Start Your Project Inquiry</a>\\n      <p class=\\"cta__note\\">Or call <a href=\\"tel:9257842798\\">925-784-2798</a></p>\\n    </div>\\n  </section>\\n\\n  <footer class=\\"footer\\">\\n    <div class=\\"container footer__inner\\">\\n      <div class=\\"footer__brand\\">\\n        <span class=\\"footer__logo\\">RIDGECREST DESIGNS</span>\\n        <p class=\\"footer__tagline\\">Luxury Design-Build · Est. 2013</p>\\n        <p class=\\"footer__tagline\\" style=\\"font-style:italic; opacity:0.6\\">Experience the Ridgecrest difference.</p>\\n        <p class=\\"footer__address\\">5502 Sunol Blvd, Suite 100<br>Pleasanton, CA 94566</p>\\n        <p><a href=\\"tel:9257842798\\">925-784-2798</a> · <a href=\\"mailto:info@ridgecrestdesigns.com\\">info@ridgecrestdesigns.com</a></p>\\n      </div>\\n      <div class=\\"footer__nav\\">\\n        <div class=\\"footer__col\\">\\n          <p class=\\"footer__col-head\\">Company</p>\\n          <a href=\\"about.html\\">About</a>\\n          <a href=\\"team.html\\">Team</a>\\n          <a href=\\"process.html\\">Process</a>\\n          <a href=\\"portfolio.html\\">Portfolio</a>\\n        </div>\\n        <div class=\\"footer__col\\">\\n          <p class=\\"footer__col-head\\">Services</p>\\n          <a href=\\"services/custom-home-builder-danville.html\\">Custom Homes</a>\\n          <a href=\\"services/whole-house-remodel-danville.html\\">Whole House Remodels</a>\\n          <a href=\\"services/kitchen-remodel-danville.html\\">Kitchen Remodels</a>\\n          <a href=\\"services/bathroom-remodel-danville.html\\">Bathroom Remodels</a>\\n        </div>\\n                <div class=\\"footer__col\\">\\n          <p class=\\"footer__col-head\\">Service Areas</p>\\n          <a href=\\"services/alamo.html\\">Alamo</a>\\n          <a href=\\"services/danville.html\\">Danville</a>\\n          <a href=\\"services/diablo.html\\">Diablo</a>\\n          <a href=\\"services/dublin.html\\">Dublin</a>\\n          <a href=\\"services/lafayette.html\\">Lafayette</a>\\n          <a href=\\"services/moraga.html\\">Moraga</a>\\n          <a href=\\"services/orinda.html\\">Orinda</a>\\n          <a href=\\"services/pleasanton.html\\">Pleasanton</a>\\n          <a href=\\"services/rossmoor.html\\">Rossmoor</a>\\n          <a href=\\"services/san-ramon.html\\">San Ramon</a>\\n          <a href=\\"services/sunol.html\\">Sunol</a>\\n          <a href=\\"services/walnut-creek.html\\">Walnut Creek</a>\\n        </div>\\n        <div class=\\"footer__col\\">\\n          <p class=\\"footer__col-head\\">Connect</p>\\n          <a href=\\"https://elevate-scheduling-6b2fdec8.base44.app/ProjectInquiryForm\\">Start a Project</a>\\n          <a href=\\"contact.html\\">Contact Us</a>\\n          <a href=\\"/blog\\">The RD Edit</a>\\n          <a href=\\"https://www.instagram.com/ridgecrestdesigns\\" target=\\"_blank\\" rel=\\"noopener\\">Instagram</a>\\n          <a href=\\"https://www.facebook.com/ridgecrestdesigns\\" target=\\"_blank\\" rel=\\"noopener\\">Facebook</a>\\n          <a href=\\"https://www.houzz.com/pro/ridgecrestdesigns\\" target=\\"_blank\\" rel=\\"noopener\\">Houzz</a>\\n        </div>\\n      </div>\\n    </div>\\n    <div class=\\"footer__bottom\\">\\n      <div class=\\"container\\">\\n        <p>© 2026 Ridgecrest Designs. All rights reserved.</p>\\n        <p>Licensed &amp; Insured · California Contractor · <a href=\\"sitemap.html\\">Site Map</a></p>\\n      </div>\\n    </div>\\n  </footer>\\n\\n  <script src=\\"js/main.js\\"></script>\\n</body>\\n</html>\\n"}	about	t	pages
