00;500&display=block\\" rel=\\"stylesheet\\" />\\n  <style>\\n    .fade-in { opacity: 0; transform: translateY(20px); transition: opacity 0.6s ease, transform 0.6s ease; }\\n    .fade-in.visible { opacity: 1; transform: none; }\\n  </style>\\n</head>\\n<body>\\n\\n  <nav class=\\"nav nav--scrolled\\" id=\\"nav\\">\\n    <a href=\\"index.html\\" class=\\"nav__logo\\">RIDGECREST DESIGNS</a>\\n    <button class=\\"nav__toggle\\" id=\\"navToggle\\" aria-label=\\"Menu\\">\\n      <span></span><span></span><span></span>\\n    </button>\\n    <ul class=\\"nav__links\\" id=\\"navLinks\\">\\n      <li><a href=\\"about.html\\">About</a></li>\\n      <li><a href=\\"process.html\\">Process</a></li>\\n      <li><a href=\\"services.html\\">Services</a></li>\\n      <li><a href=\\"portfolio.html\\">Portfolio</a></li>\\n      <li><a href=\\"/blog\\">The RD Edit</a></li>\\n      <li><a href=\\"team.html\\">Team</a></li>\\n      <li><a href=\\"contact.html\\" class=\\"nav__cta\\">Start a Project</a></li>\\n    </ul>\\n  </nav>\\n\\n  <div class=\\"page-hero page-hero--service\\">\\n    <p class=\\"page-hero__eyebrow\\">The People</p>\\n    <h1 class=\\"page-hero__title\\">The team behind<br><em>every project</em></h1>\\n    <p class=\\"page-hero__sub\\">Architects, designers, project managers, and craftsmen — each selected for their mastery and their commitment to your outcome.</p>\\n  </div>\\n\\n  <!-- Founder section — Henry Batteate -->\\n  <section class=\\"founder-section\\">\\n    <div class=\\"container\\">\\n      <div class=\\"founder-layout\\">\\n        <div class=\\"founder-bio\\">\\n          <p class=\\"founder-bio__label\\">Founder</p>\\n          <h2 class=\\"founder-bio__name\\" id=\\"founderName\\">Henry Batteate</h2>\\n          <p class=\\"founder-bio__role\\" id=\\"founderRole\\">Owner &amp; Principal</p>\\n          <p class=\\"founder-bio__text\\" id=\\"founderBio\\"></p>\\n        </div>\\n        <div class=\\"founder-photo\\" data-card-id=\\"team-member-1\\" id=\\"founderPhoto\\"></div>\\n      </div>\\n    </div>\\n  </section>\\n\\n  <section class=\\"section\\">\\n    <div class=\\"container\\">\\n      <div class=\\"team-grid\\" id=\\"teamGrid\\">\\n        <!-- Populated dynamically from /api/team (excludes founder) -->\\n      </div>\\n    </div>\\n  </section>\\n\\n  <section class=\\"section section--accent\\" style=\\"text-align:center\\">\\n    <div class=\\"container container--narrow\\">\\n      <p class=\\"section__label\\">Join the Team</p>\\n      <h2 class=\\"section__headline\\" style=\\"margin-bottom:1.2rem\\">We're selective.<br><em>So are our people.</em></h2>\\n      <p style=\\"color:#555; max-width:520px; margin:0 auto 2rem; font-size:0.92rem; line-height:1.85\\">We look for skilled professionals who hold themselves to the same standard we hold every project. If that's you, reach out.</p>\\n      <a href=\\"mailto:info@ridgecrestdesigns.com\\" class=\\"btn btn--dark\\">Contact Us →</a>\\n    </div>\\n  </section>\\n\\n  <footer class=\\"footer\\">\\n    <div class=\\"container footer__inner\\">\\n      <div class=\\"footer__brand\\">\\n        <span class=\\"footer__logo\\">RIDGECREST DESIGNS</span>\\n        <p class=\\"footer__tagline\\">Luxury Design-Build · Est. 2013</p>\\n        <p class=\\"footer__tagline\\" style=\\"font-style:italic; opacity:0.6\\">Experience the Ridgecrest difference.</p>\\n        <p class=\\"footer__address\\">5502 Sunol Blvd, Suite 100<br>Pleasanton, CA 94566</p>\\n        <p><a href=\\"tel:9257842798\\">925-784-2798</a> · <a href=\\"mailto:info@ridgecrestdesigns.com\\">info@ridgecrestdesigns.com</a></p>\\n      </div>\\n      <div class=\\"footer__nav\\">\\n        <div class=\\"footer__col\\">\\n          <p class=\\"footer__col-head\\">Company</p>\\n          <a href=\\"about.html\\">About</a>\\n          <a href=\\"team.html\\">Team</a>\\n          <a href=\\"process.html\\">Process</a>\\n          <a href=\\"portfolio.html\\">Portfolio</a>\\n        </div>\\n        <div class=\\"footer__col\\">\\n          <p class=\\"footer__col-head\\">Services</p>\\n          <a href=\\"services/custom-home-builder-danville.html\\">Custom Homes</a>\\n          <a href=\\"services/whole-house-remodel-danville.html\\">Whole House Remodels</a>\\n          <a href=\\"services/kitchen-remodel-danville.html\\">Kitchen Remodels</a>\\n          <a href=\\"services/bathroom-remodel-danville.html\\">Bathroom Remodels</a>\\n        </div>\\n                <div class=\\"footer__col\\">\\n          <p class=\\"footer__col-head\\">Service Areas</p>\\n          <a href=\\"services/alamo.html\\">Alamo</a>\\n          <a href=\\"services/danville.html\\">Danville</a>\\n          <a href=\\"services/diablo.html\\">Diablo</a>\\n          <a href=\\"services/dublin.html\\">Dublin</a>\\n          <a href=\\"services/lafayette.html\\">Lafayette</a>\\n          <a href=\\"services/moraga.html\\">Moraga</a>\\n          <a href=\\"services/orinda.html\\">Orinda</a>\\n          <a href=\\"services/pleasanton.html\\">Pleasanton</a>\\n          <a href=\\"services/rossmoor.html\\">Rossmoor</a>\\n          <a href=\\"services/san-ramon.html\\">San Ramon</a>\\n          <a href=\\"services/sunol.html\\">Sunol</a>\\n          <a href=\\"services/walnut-creek.html\\">Walnut Creek</a>\\n        </div>\\n        <div class=\\"footer__col\\">\\n          <p class=\\"footer__col-head\\">Connect</p>\\n          <a href=\\"https://elevate-scheduling-6b2fdec8.base44.app/ProjectInquiryForm\\">Start a Project</a>\\n          <a href=\\"contact.html\\">Contact Us</a>\\n          <a href=\\"/blog\\">The RD Edit</a>\\n          <a href=\\"https://www.instagram.com/ridgecrestdesigns\\" target=\\"_blank\\" rel=\\"noopener\\">Instagram</a>\\n          <a href=\\"https://www.facebook.com/ridgecrestdesigns\\" target=\\"_blank\\" rel=\\"noopener\\">Facebook</a>\\n          <a href=\\"https://www.houzz.com/pro/ridgecrestdesigns\\" target=\\"_blank\\" rel=\\"noopener\\">Houzz</a>\\n        </div>\\n      </div>\\n    </div>\\n    <div class=\\"footer__bottom\\">\\n      <div class=\\"container\\">\\n        <p>© 2026 Ridgecrest Designs. All rights reserved.</p>\\n        <p>Licensed &amp; Insured · California Contractor · <a href=\\"sitemap.html\\">Site Map</a></p>\\n      </div>\\n    </div>\\n  </footer>\\n\\n  <script src=\\"js/main.js\\"></script>\\n  <script>\\n    (function() {\\n      var grid = document.getElementById('teamGrid');\\n      fetch('/api/team')\\n        .then(function(r) { return r.json(); })\\n        .then(function(members) {\\n          if (!members.length) return;\\n\\n          // Populate founder bio from DB (id=1)\\n          var founder = members.find(function(m) { return m.id === 1; });\\n          if (founder) {\\n            var bioEl = document.getElementById('founderBio');\\n            if (bioEl && founder.bio) bioEl.textContent = founder.bio;\\n          }\\n\\n          // Grid: exclude founder (id=1)\\n          var rest = members.filter(function(m) { return m.id !== 1; });\\n          if (!rest.length) return;\\n          grid.innerHTML = rest.map(function(m) {\\n            var photoStyle = m.photo\\n              ? 'background-image:url(\\\\'' + m.photo + '\\\\'); background-size:cover; background-position:center top;'\\n              : 'background:#e8e0d5;';\\n            return '<div class=\\"team-card fade-in\\">' +\\n              '<div class=\\"team-card__photo\\" style=\\"' + photoStyle + '\\"></div>' +\\n              '<h3 class=\\"team-card__name\\">' + m.name + '</h3>' +\\n              '<p class=\\"team-card__title\\">' + m.role + '</p>' +\\n              '<p class=\\"team-card__bio\\">' + (m.bio || '') + '</p>' +\\n              '</div>';\\n          }).join('');\\n\\n          // Trigger fade-in for cards now in DOM\\n          grid.querySelectorAll('.team-card').forEach(function(el) {\\n            var r = el.getBoundingClientRect();\\n            if (r.top < window.innerHeight && r.bottom > 0) {\\n              el.classList.add('visible');\\n            } else {\\n              var obs = new IntersectionObserver(function(entries) {\\n                entries.forEach(function(e) {\\n                  if (e.isIntersecting) { e.target.classList.add('visible'); obs.unobserve(e.target); }\\n                });\\n              }, { threshold: 0.1 });\\n              obs.observe(el);\\n            }\\n          });\\n        })\\n        .catch(function() { /* silently keep empty grid */ });\\n    })();\\n  </script>\\n</body>\\n</html>\\n"}	team	f	pages
459	2026-04-02 05:12:17.916125+00	Text edit: team	page_text_edit	{"slug": "team", "file_path": "/home/claudeuser/agent/preview/team.html", "original_html": "<!DOCTYPE html>\\n\\n<html lang=\\"en\\">\\n<head>\\n<meta charset=\\"utf-8\\"/>\\n<meta content=\\"width=device-width, initial-scale=1.0\\" name=\\"viewport\\"/>\\n<title>Team — Ridgecrest Designs | Design-Build Experts, Pleasanton CA</title>\\n<meta content=\\"Meet the Ridgecrest Designs team — architects, designers, and project managers bringing luxury custom homes and remodels to life across the East Bay.\\" name=\\"description\\"/>\\n<link href=\\"https://www.ridgecrestdesigns.com/team\\" rel=\\"canonical\\"/>\\n<meta content=\\"Our Team — Ridgecrest Designs\\" property=\\"og:title\\"/>\\n<meta content=\\"Meet the expert design-build team behind Ridgecrest Designs — architects, designers, project managers and craftsmen serving Pleasanton, Danville, Alamo and the East Bay.\\" property=\\"og:description\\"/>\\n<meta content=\\"https://www.ridgecrestdesigns.com/og-image.jpg\\" property=\\"og:image\\"/>\\n<meta content=\\"https://www.ridgecrestdesigns.com/team\\" property=\\"og:url\\"/>\\n<meta content=\\"summary_large_image\\" name=\\"twitter:card\\"/>\\n<meta content=\\"Our Team — Ridgecrest Designs\\" name=\\"twitter:title\\"/>\\n<meta content=\\"Meet the expert design-build team behind Ridgecrest Designs — architects, designers, project managers and craftsmen serving Pleasanton, Danville, Alamo and the East Bay.\\" name=\\"twitter:description\\"/>\\n<meta content=\\"https://www.ridgecrestdesigns.com/og-image.jpg\\" name=\\"twitter:image\\"/>\\n<link href=\\"css/main.css\\" rel=\\"stylesheet\\">\\n<link href=\\"https://fonts.googleapis.com\\" rel=\\"preconnect\\"/>\\n<link crossorigin=\\"\\" href=\\"https://fonts.gstatic.com\\" rel=\\"preconnect\\"/>\\n<link href=\\"https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,500;1,300;1,400&amp;family=Jost:wght@300;400;500&amp;display=block\\" rel=\\"stylesheet\\"/>\\n<style>\\n    .fade-in { opacity: 0; transform: translateY(20px); transition: opacity 0.6s ease, transform 0.6s ease; }\\n    .fade-in.visible { opacity: 1; transform: none; }\\n  </style>\\n</link></head>\\n<body>\\n<nav class=\\"nav nav--scrolled\\" id=\\"nav\\">\\n<a class=\\"nav__logo\\" href=\\"index.html\\">RIDGECREST DESIGNS</a>\\n<button aria-label=\\"Menu\\" class=\\"nav__toggle\\" id=\\"navToggle\\">\\n<span></span><span></span><span></span>\\n</button>\\n<ul class=\\"nav__links\\" id=\\"navLinks\\">\\n<li><a href=\\"about.html\\">About</a></li>\\n<li><a href=\\"process.html\\">Process</a></li>\\n<li><a href=\\"services.html\\">Services</a></li>\\n<li><a href=\\"portfolio.html\\">Portfolio</a></li>\\n<li><a href=\\"/blog\\">The RD Edit</a></li>\\n<li><a href=\\"team.html\\">Team</a></li>\\n<li><a class=\\"nav__cta\\" href=\\"contact.html\\">Start a Project</a></li>\\n</ul>\\n</nav>\\n<div class=\\"page-hero page-hero--service\\">\\n<p class=\\"page-hero__eyebrow\\">The People</p>\\n<h1 class=\\"page-hero__title\\">The team behind<br/><em>every project</em></h1>\\n<p class=\\"page-hero__sub\\">Architects, designers, project managers, and craftsmen — each selected for their mastery and their commitment to your outcome.</p>\\n</div>\\n<!-- Founder section — Henry Batteate -->\\n<section class=\\"founder-section\\">\\n<div class=\\"container\\">\\n<div class=\\"founder-layout\\">\\n<div class=\\"founder-bio\\">\\n<p class=\\"founder-bio__label\\">Founder</p>\\n<h2 class=\\"founder-bio__name\\" id=\\"founderName\\">Henry Batteate</h2>\\n<p class=\\"founder-bio__role\\" id=\\"founderRole\\">Owner &amp; Principal</p>\\n<p class=\\"founder-bio__text\\" id=\\"founderBio\\"></p>\\n</div>\\n<div class=\\"founder-photo\\" data-card-id=\\"team-member-1\\" id=\\"founderPhoto\\"></div>\\n</div>\\n</div>\\n</section>\\n<section class=\\"section\\">\\n<div class=\\"container\\">\\n<div class=\\"team-grid\\" id=\\"teamGrid\\">\\n<!-- Populated dynamically from /api/team (excludes founder) -->\\n</div>\\n</div>\\n</section>\\n<section class=\\"section section--accent\\" style=\\"text-align:center\\">\\n<div class=\\"container container--narrow\\">\\n<p class=\\"section__label\\"><div>                                    </div><div>He met his wife when he was 16 and she was just 14. More than thirty years later, she works alongside him full-time at Ridgecrest, as does their oldest daughter. What started as a young love became the foundation of a family business built on the same values as every home they build — commitment, precision, and care.                                                    </div><div>From bull riding champion to designing and building homes, Henry founded Ridgecrest Designs with a passion for architecture, design, and hands-on craftsmanship, and that passion is visible in every detail. He oversees each project personally. At his shop in Livermore, along with his daughters he personally builds every custom hood, and architectural metalwork, that goes into a Ridgecrest home. Nothing is off the shelf. Everything is custom made.                                                                                        </div><div>What makes him proudest, though, is his team. Teaching and empowering the Ridgecrest team, instills the confidence wisdom and knowledge they need to succeed long after he is gone. Henry understands that what he says and how he says it matters. Words either build up or tear down and he peaks with intention to build up everyone around him..             </div><div><br/></div><div>That is Henry Batteate. A builder of homes. A builder of people. A maker, in every sense of the word.</div></p>\\n<h2 class=\\"section__headline\\" style=\\"margin-bottom:1.2rem\\">We're selective.<br/><em>So are our people.</em></h2>\\n<p style=\\"color:#555; max-width:520px; margin:0 auto 2rem; font-size:0.92rem; line-height:1.85\\">We look for skilled professionals who hold themselves to the same standard we hold every project. If that's you, reach out.</p>\\n<a class=\\"btn btn--dark\\" href=\\"mailto:info@ridgecrestdesigns.com\\">Contact Us →</a>\\n</div>\\n</section>\\n<footer class=\\"footer\\">\\n<div class=\\"container footer__inner\\">\\n<div class=\\"footer__brand\\">\\n<span class=\\"footer__logo\\">RIDGECREST DESIGNS</span>\\n<p class=\\"footer__tagline\\">Luxury Design-Build · Est. 2013</p>\\n<p class=\\"footer__tagline\\" style=\\"font-style:italic; opacity:0.6\\">Experience the Ridgecrest difference.</p>\\n<p class=\\"footer__address\\">5502 Sunol Blvd, Suite 100<br/>Pleasanton, CA 94566</p>\\n<p><a href=\\"tel:9257842798\\">925-784-2798</a> · <a href=\\"mailto:info@ridgecrestdesigns.com\\">info@ridgecrestdesigns.com</a></p>\\n</div>\\n<div class=\\"footer__nav\\">\\n<div class=\\"footer__col\\">\\n<p class=\\"footer__col-head\\">Company</p>\\n<a href=\\"about.html\\">About</a>\\n<a href=\\"team.html\\">Team</a>\\n<a href=\\"process.html\\">Process</a>\\n<a href=\\"portfolio.html\\">Portfolio</a>\\n</div>\\n<div class=\\"footer__col\\">\\n<p class=\\"footer__col-head\\">Services</p>\\n<a href=\\"services/custom-home-builder-danville.html\\">Custom Homes</a>\\n<a href=\\"services/whole-house-remodel-danville.html\\">Whole House Remodels</a>\\n<a href=\\"services/kitchen-remodel-danville.html\\">Kitchen Remodels</a>\\n<a href=\\"services/bathroom-remodel-danville.html\\">Bathroom Remodels</a>\\n</div>\\n<div class=\\"footer__col\\">\\n<p class=\\"footer__col-head\\">Service Areas</p>\\n<a href=\\"services/alamo.html\\">Alamo</a>\\n<a href=\\"services/danville.html\\">Danville</a>\\n<a href=\\"services/diablo.html\\">Diablo</a>\\n<a href=\\"services/dublin.html\\">Dublin</a>\\n<a href=\\"services/lafayette.html\\">Lafayette</a>\\n<a href=\\"services/moraga.html\\">Moraga</a>\\n<a href=\\"services/orinda.html\\">Orinda</a>\\n<a href=\\"services/pleasanton.html\\">Pleasanton</a>\\n<a href=\\"services/rossmoor.html\\">Rossmoor</a>\\n<a href=\\"services/san-ramon.html\\">San Ramon</a>\\n<a href=\\"services/sunol.html\\">Sunol</a>\\n<a href=\\"services/walnut-creek.html\\">Walnut Creek</a>\\n</div>\\n<div class=\\"footer__col\\">\\n<p class=\\"footer__col-head\\">Connect</p>\\n<a href=\\"https://elevate-scheduling-6b2fdec8.base44.app/ProjectInquiryForm\\">Start a Project</a>\\n<a href=\\"contact.html\\">Contact Us</a>\\n<a href=\\"/blog\\">The RD Edit</a>\\n<a href=\\"https://www.instagram.com/ridgecrestdesigns\\" rel=\\"noopener\\" target=\\"_blank\\">Instagram</a>\\n<a href=\\"https://www.facebook.com/ridgecrestdesigns\\" rel=\\"noopener\\" target=\\"_blank\\">Facebook</a>\\n<a href=\\"https://www.houzz.com/pro/ridgecrestdesigns\\" rel=\\"noopener\\" target=\\"_blank\\">Houzz</a>\\n</div>\\n</div>\\n</div>\\n<div class=\\"footer__bottom\\">\\n<div class=\\"container\\">\\n<p>© 2026 Ridgecrest Designs. All rights reserved.</p>\\n<p>Licensed &amp; Insured · California Contractor · <a href=\\"sitemap.html\\">Site Map</a></p>\\n</div>\\n</div>\\n</footer>\\n<script src=\\"js/main.js\\"></script>\\n<script>\\n    (function() {\\n      var grid = document.getElementById('teamGrid');\\n      fetch('/api/team')\\n        .then(function(r) { return r.json(); })\\n        .then(function(members) {\\n          if (!members.length) return;\\n\\n          // Populate founder bio from DB (id=1)\\n          var founder = members.find(function(m) { return m.id === 1; });\\n          if (founder) {\\n            var bioEl = document.getElementById('founderBio');\\n            if (bioEl && founder.bio) bioEl.textContent = founder.bio;\\n          }\\n\\n          // Grid: exclude founder (id=1)\\n          var rest = members.filter(function(m) { return m.id !== 1; });\\n          if (!rest.length) return;\\n          grid.innerHTML = rest.map(function(m) {\\n            var photoStyle = m.photo\\n              ? 'background-image:url(\\\\'' + m.photo + '\\\\'); background-size:cover; background-position:center top;'\\n              : 'background:#e8e0d5;';\\n            return '<div class=\\"team-card fade-in\\">' +\\n              '<div class=\\"team-card__photo\\" style=\\"' + photoStyle + '\\"></div>' +\\n              '<h3 class=\\"team-card__name\\">' + m.name + '</h3>' +\\n              '<p class=\\"team-card__title\\">' + m.role + '</p>' +\\n              '<p class=\\"team-card__bio\\">' + (m.bio || '') + '</p>' +\\n              '</div>';\\n          }).join('');\\n\\n          // Trigger fade-in for cards now in DOM\\n          grid.querySelectorAll('.team-card').forEach(function(el) {\\n            var r = el.getBoundingClientRect();\\n            if (r.top < window.innerHeight && r.bottom > 0) {\\n              el.classList.add('visible');\\n            } else {\\n              var obs = new IntersectionObserver(function(entries) {\\n                entries.forEach(function(e) {\\n                  if (e.isIntersecting) { e.target.classList.add('visible'); obs.unobserve(e.target); }\\n                });\\n              }, { threshold: 0.1 });\\n              obs.observe(el);\\n            }\\n          });\\n        })\\n        .catch(function() { /* silently keep empty grid */ });\\n    })();\\n  </script>\\n</body>\\n</html>\\n"}	team	f	pages
