──────────────────────── -->\\n</head>\\n<body>\\n<!-- NAV -->\\n<nav class=\\"nav\\" id=\\"nav\\">\\n<a class=\\"nav__logo\\" href=\\"index.html\\">RIDGECREST DESIGNS</a>\\n<button aria-label=\\"Menu\\" class=\\"nav__toggle\\" id=\\"navToggle\\">\\n<span></span><span></span><span></span>\\n</button>\\n<ul class=\\"nav__links\\" id=\\"navLinks\\">\\n<li><a href=\\"about.html\\">About</a></li>\\n<li><a href=\\"process.html\\">Process</a></li>\\n<li><a href=\\"services.html\\">Services</a></li>\\n<li><a href=\\"portfolio.html\\">Portfolio</a></li>\\n<li><a href=\\"/blog\\">The RD Edit</a></li>\\n<li><a href=\\"team.html\\">Team</a></li>\\n<li><a class=\\"nav__cta\\" href=\\"https://elevate-scheduling-6b2fdec8.base44.app/ProjectInquiryForm\\">Start a Project</a></li>\\n</ul>\\n</nav>\\n<!-- HERO -->\\n<section class=\\"hero\\">\\n<div class=\\"hero__bg\\"></div>\\n<div class=\\"hero__overlay\\"></div>\\n<div class=\\"hero__content\\">\\n<p class=\\"hero__eyebrow\\">Luxury Design-Build · East Bay, California &amp; Weatherford, TX</p>\\n<h1 class=\\"hero__headline\\">Your Vision,<br/><em>Flawlessly Built</em></h1>\\n<p class=\\"hero__sub\\">Photo-realistic renders. Integrated delivery. Flawless execution.<br/><em>Experience the Ridgecrest difference.</em></p>\\n<div class=\\"hero__actions\\">\\n<a class=\\"btn btn--primary\\" href=\\"https://elevate-scheduling-6b2fdec8.base44.app/ProjectInquiryForm\\">Start Your Project</a>\\n<a class=\\"btn btn--ghost\\" href=\\"portfolio.html\\">View Portfolio</a>\\n</div>\\n</div>\\n<div class=\\"hero__scroll\\"><span></span></div>\\n</section>\\n<!-- INTRO -->\\n<section class=\\"intro section\\">\\n<div class=\\"container container--narrow\\">\\n<p class=\\"intro__label\\">Est. 2013 · Pleasanton, CA</p>\\n<h2 class=\\"intro__headline\\">We design and build homes the way<br/><em>they were meant to be experienced.</em></h2>\\n<p class=\\"intro__body\\">We work best with homeowners who see the value in hiring a team of professionals, trusts and appreciate a firm that executes it without compromise. If that's you, we should talk.</p>\\n</div>\\n</section>\\n<!-- SERVICES -->\\n<section class=\\"services section section--dark\\">\\n<div class=\\"container\\">\\n<div class=\\"section__header\\">\\n<p class=\\"section__label\\">What We Build</p>\\n<h2 class=\\"section__headline\\">Expertise across every scale<br/>of residential work</h2>\\n</div>\\n<div class=\\"services__grid\\">\\n<div class=\\"service-card\\" data-card-id=\\"service-custom-homes\\">\\n<div class=\\"service-card__num\\">01</div>\\n<h3 class=\\"service-card__title\\">Custom Homes</h3>\\n<p class=\\"service-card__body\\">Luxury custom homes from $5M to $10M+. We manage design, engineering, permitting, and construction under one roof — with photo-realistic renders before we break ground.</p>\\n<a class=\\"service-card__link\\" href=\\"custom-homes.html\\">Learn More →</a>\\n</div>\\n<div class=\\"service-card\\" data-card-id=\\"service-whole-house-remodels\\">\\n<div class=\\"service-card__num\\">02</div>\\n<h3 class=\\"service-card__title\\">Whole House Remodels</h3>\\n<p class=\\"service-card__body\\">Complete home transformations starting at $1M. We handle the full scope — architecture, structural, interiors, and construction — with zero gaps in accountability.</p>\\n<a class=\\"service-card__link\\" href=\\"whole-house-remodels.html\\">Learn More →</a>\\n</div>\\n<div class=\\"service-card\\" data-card-id=\\"service-kitchen-remodels\\">\\n<div class=\\"service-card__num\\">03</div>\\n<h3 class=\\"service-card__title\\">Kitchen Remodels</h3>\\n<p class=\\"service-card__body\\">High-specification kitchen renovations starting at $150,000. Custom cabinetry, stonework, and premium appliances — designed and built to last decades.</p>\\n<a class=\\"service-card__link\\" href=\\"kitchen-remodels.html\\">Learn More →</a>\\n</div>\\n<div class=\\"service-card\\" data-card-id=\\"service-bathroom-remodels\\">\\n<div class=\\"service-card__num\\">04</div>\\n<h3 class=\\"service-card__title\\">Bathroom Remodels</h3>\\n<p class=\\"service-card__body\\">Master and primary bathroom renovations starting at $60,000. Spa-quality craftsmanship with materials and finishes chosen for longevity and visual impact.</p>\\n<a class=\\"service-card__link\\" href=\\"bathroom-remodels.html\\">Learn More →</a>\\n</div>\\n</div>\\n</div>\\n</section>\\n<!-- DIFFERENTIATORS -->\\n<section class=\\"diff section\\">\\n<div class=\\"container diff__layout\\">\\n<div class=\\"diff__visual\\">\\n<div class=\\"diff__visual-inner\\">\\n<div class=\\"diff__quote\\">“See it before we build it.”</div>\\n<div class=\\"diff__stats\\">\\n<div class=\\"diff__stat\\">\\n<span class=\\"diff__num\\">12+</span>\\n<span class=\\"diff__lbl\\">Years of Experience</span>\\n</div>\\n<div class=\\"diff__stat\\">\\n<span class=\\"diff__num\\">100%</span>\\n<span class=\\"diff__lbl\\">Design-Build Delivery</span>\\n</div>\\n</div>\\n</div>\\n</div>\\n<div class=\\"diff__content\\">\\n<p class=\\"section__label\\">Why Ridgecrest</p>\\n<h2 class=\\"section__headline\\">See your home before<br/><em>we build it</em></h2>\\n<p class=\\"diff__body\\">Every project begins with photo-realistic renders that give you visual certainty — not approximations. You'll see your custom home or remodel in precise detail before a single permit is filed.</p>\\n<ul class=\\"diff__list\\">\\n<li>\\n<div class=\\"diff__icon\\">→</div>\\n<div>\\n<strong>Integrated Design-Build</strong>\\n<span>One team. One contract. No gaps.</span>\\n</div>\\n</li>\\n<li>\\n<div class=\\"diff__icon\\">→</div>\\n<div>\\n<strong>Permitting &amp; Engineering Expertise</strong>\\n<span>We know California code inside and out.</span>\\n</div>\\n</li>\\n<li>\\n<div class=\\"diff__icon\\">→</div>\\n<div>\\n<strong>Specialized Teams</strong>\\n<span>The right craftsmen for every phase.</span>\\n</div>\\n</li>\\n<li>\\n<div class=\\"diff__icon\\">→</div>\\n<div>\\n<strong>Clear Communication</strong>\\n<span>Progress updates built into our process.</span>\\n</div>\\n</li>\\n</ul>\\n<a class=\\"btn btn--dark\\" href=\\"process.html\\">Our Process →</a>\\n</div>\\n</div>\\n</section>\\n<!-- PROCESS STRIP -->\\n<section class=\\"process-strip section section--accent\\">\\n<div class=\\"container\\">\\n<div class=\\"section__header\\">\\n<p class=\\"section__label\\">Our Approach</p>\\n<h2 class=\\"section__headline\\">Five stages. Zero surprises.</h2>\\n</div>\\n<div class=\\"process-strip__steps\\">\\n<div class=\\"step\\">\\n<div class=\\"step__num\\">1</div>\\n<div class=\\"step__title\\">Consultation</div>\\n<div class=\\"step__desc\\">We learn your vision, goals, and budget in a focused initial meeting.</div>\\n</div>\\n<div class=\\"step__line\\"></div>\\n<div class=\\"step\\">\\n<div class=\\"step__num\\">2</div>\\n<div class=\\"step__title\\">Design</div>\\n<div class=\\"step__desc\\">Custom floor plans, elevations, and photo-realistic 3D renders.</div>\\n</div>\\n<div class=\\"step__line\\"></div>\\n<div class=\\"step\\">\\n<div class=\\"step__num\\">3</div>\\n<div class=\\"step__title\\">Budget &amp; Proposal</div>\\n<div class=\\"step__desc\\">Detailed scope with transparent pricing and realistic timelines.</div>\\n</div>\\n<div class=\\"step__line\\"></div>\\n<div class=\\"step\\">\\n<div class=\\"step__num\\">4</div>\\n<div class=\\"step__title\\">Build</div>\\n<div class=\\"step__desc\\">Expert construction with active project management throughout.</div>\\n</div>\\n<div class=\\"step__line\\"></div>\\n<div class=\\"step\\">\\n<div class=\\"step__num\\">5</div>\\n<div class=\\"step__title\\">Completion</div>\\n<div class=\\"step__desc\\">Final walkthrough, quality sign-off, and delivery of your home.</div>\\n</div>\\n</div>\\n<div class=\\"process-strip__cta\\">\\n<a class=\\"btn btn--outline\\" href=\\"process.html\\">Full Process Breakdown</a>\\n</div>\\n</div>\\n</section>\\n<!-- PORTFOLIO TEASER -->\\n<section class=\\"portfolio-strip section section--dark\\">\\n<div class=\\"container\\">\\n<div class=\\"section__header section__header--split\\">\\n<div>\\n<p class=\\"section__label\\">Recent Work</p>\\n<h2 class=\\"section__headline\\">Selected projects</h2>\\n</div>\\n<a class=\\"btn btn--ghost-sm\\" href=\\"portfolio.html\\">View All Work →</a>\\n</div>\\n<div class=\\"portfolio-strip__grid\\">\\n<a class=\\"portfolio-card portfolio-card--large\\" href=\\"danville-dream.html\\">\\n<div aria-label=\\"Danville Dream Home — luxury home remodel by Ridgecrest Designs\\" class=\\"portfolio-card__img portfolio-card__img--1\\" role=\\"img\\"></div>\\n<div class=\\"portfolio-card__info\\">\\n<span class=\\"portfolio-card__loc\\">Danville, CA</span>\\n<h3 class=\\"portfolio-card__name\\">Danville Dream Home</h3>\\n<span class=\\"portfolio-card__type\\">Luxury Home Remodel</span>\\n</div>\\n</a>\\n<a class=\\"portfolio-card\\" href=\\"lafayette-bistro.html\\">\\n<div aria-label=\\"Pleasanton Custom Home — custom home by Ridgecrest Designs\\" class=\\"portfolio-card__img portfolio-card__img--2\\" role=\\"img\\"></div>\\n<div class=\\"portfolio-card__info\\">\\n<span class=\\"portfolio-card__loc\\">Lafayette, CA</span>\\n<h3 class=\\"portfolio-card__name\\">Lafayette Modern Bistro</h3>\\n<span class=\\"portfolio-card__type\\">Kitchen Remodel</span>\\n</div>\\n</a>\\n<a class=\\"portfolio-card\\" href=\\"pleasanton-custom.html\\">\\n<div aria-label=\\"Lafayette Modern Bistro — kitchen remodel by Ridgecrest Designs\\" class=\\"portfolio-card__img portfolio-card__img--3\\" role=\\"img\\"></div>\\n<div class=\\"portfolio-card__info\\">\\n<span class=\\"portfolio-card__loc\\">Pleasanton, CA</span>\\n<h3 class=\\"portfolio-card__name\\">Pleasanton Custom Home</h3>\\n<span class=\\"portfolio-card__type\\">Custom Home</span>\\n</div>\\n</a>\\n<a class=\\"portfolio-card\\" href=\\"alamo-luxury.html\\">\\n<div aria-label=\\"Alamo Luxury Home — luxury remodel by Ridgecrest Designs\\" class=\\"portfolio-card__img portfolio-card__img--4\\" role=\\"img\\"></div>\\n<div class=\\"portfolio-card__info\\">\\n<span class=\\"portfolio-card__loc\\">Alamo, CA</span>\\n<h3 class=\\"portfolio-card__name\\">Alamo Luxury Home</h3>\\n<span class=\\"portfolio-card__type\\">Luxury Remodel</span>\\n</div>\\n</a>\\n</div>\\n</div>\\n</section>\\n<!-- LOCATIONS -->\\n<section class=\\"locations section\\">\\n<div class=\\"container\\">\\n<div class=\\"section__header\\">\\n<p class=\\"section__label\\">Service Areas</p>\\n<h2 class=\\"section__headline\\">Serving the East Bay's<br/><em>most discerning homeowners</em></h2>\\n</div>\\n<div class=\\"locations__list\\">\\n<span>Pleasanton</span><span>Walnut Creek</span><span>Danville</span>\\n<span>Lafayette</span><span>Orinda</span><span>Alamo</span>\\n<span>San Ramon</span><span>Dublin</span><span>Moraga</span>\\n<span>Diablo</span><span>Rossmoor</span><span>Sunol</span>\\n</div>\\n</div>\\n</section>\\n<!-- CTA BAND -->\\n<section class=\\"cta section section--dark\\">\\n<div class=\\"container container--narrow cta__inner\\">\\n<h2 class=\\"cta__headline\\">Ready to build something<br/><em>extraordinary?</em></h2>\\n<p class=\\"cta__sub\\">Tell us about your project. We'll follow up within one business day.</p>\\n<p class=\\"cta__sub\\" style=\\"font-style:italic; margin-top:-0.5rem; color:var(--gold)\\">Click the link below to get started.</p>\\n<a class=\\"btn btn--primary btn--lg\\" href=\\"https://elevate-scheduling-6b2fdec8.base44.app/ProjectInquiryForm\\">Start Your Project Inquiry</a>\\n<p class=\\"cta__note\\">Or call us at <a href=\\"tel:9257842798\\">925-784-2798</a></p>\\n</div>\\n</section>\\n<!-- FOOTER -->\\n<footer class=\\"footer\\">\\n<div class=\\"container footer__inner\\">\\n<div class=\\"footer__brand\\">\\n<span class=\\"footer__logo\\">RIDGECREST DESIGNS</span>\\n<p class=\\"footer__tagline\\">Luxury Design-Build · Est. 2013</p>\\n<p class=\\"footer__tagline\\" style=\\"font-style:italic; opacity:0.6\\">Experience the Ridgecrest difference.</p>\\n<p class=\\"footer__address\\">5502 Sunol Blvd, Suite 100<br/>Pleasanton, CA 94566</p>\\n<p><a href=\\"tel:9257842798\\">925-784-2798</a> · <a href=\\"mailto:info@ridgecrestdesigns.com\\">info@ridgecrestdesigns.com</a></p>\\n</div>\\n<div class=\\"footer__nav\\">\\n<div class=\\"footer__col\\">\\n<p class=\\"footer__col-head\\">Company</p>\\n<a href=\\"about.html\\">About</a>\\n<a href=\\"team.html\\">Team</a>\\n<a href=\\"process.html\\">Process</a>\\n<a href=\\"portfolio.html\\">Portfolio</a>\\n</div>\\n<div class=\\"footer__col\\">\\n<p class=\\"footer__col-head\\">Services</p>\\n<a href=\\"services/custom-home-builder-danville.html\\">Custom Homes</a>\\n<a href=\\"services/whole-house-remodel-danville.html\\">Whole House Remodels</a>\\n<a href=\\"services/kitchen-remodel-danville.html\\">Kitchen Remodels</a>\\n<a href=\\"services/bathroom-remodel-danville.html\\">Bathroom Remodels</a>\\n</div>\\n<div class=\\"footer__col\\">\\n<p class=\\"footer__col-head\\">Service Areas</p>\\n<a href=\\"services/alamo.html\\">Alamo</a>\\n<a href=\\"services/danville.html\\">Danville</a>\\n<a href=\\"services/diablo.html\\">Diablo</a>\\n<a href=\\"services/dublin.html\\">Dublin</a>\\n<a href=\\"services/lafayette.html\\">Lafayette</a>\\n<a href=\\"services/moraga.html\\">Moraga</a>\\n<a href=\\"services/orinda.html\\">Orinda</a>\\n<a href=\\"services/pleasanton.html\\">Pleasanton</a>\\n<a href=\\"services/rossmoor.html\\">Rossmoor</a>\\n<a href=\\"services/san-ramon.html\\">San Ramon</a>\\n<a href=\\"services/sunol.html\\">Sunol</a>\\n<a href=\\"services/walnut-creek.html\\">Walnut Creek</a>\\n</div>\\n<div class=\\"footer__col\\">\\n<p class=\\"footer__col-head\\">Connect</p>\\n<a href=\\"https://elevate-scheduling-6b2fdec8.base44.app/ProjectInquiryForm\\">Start a Project</a>\\n<a href=\\"contact.html\\">Contact Us</a>\\n<a href=\\"/blog\\">The RD Edit</a>\\n<a href=\\"https://www.instagram.com/ridgecrestdesigns\\" rel=\\"noopener\\" target=\\"_blank\\">Instagram</a>\\n<a href=\\"https://www.facebook.com/ridgecrestdesigns\\" rel=\\"noopener\\" target=\\"_blank\\">Facebook</a>\\n<a href=\\"https://www.houzz.com/pro/ridgecrestdesigns\\" rel=\\"noopener\\" target=\\"_blank\\">Houzz</a>\\n</div>\\n</div>\\n</div>\\n<div class=\\"footer__bottom\\">\\n<div class=\\"container\\">\\n<p>© 2026 Ridgecrest Designs. All rights reserved.</p>\\n<p>Licensed &amp; Insured · California Contractor · <a href=\\"sitemap.html\\">Site Map</a></p>\\n</div>\\n</div>\\n</footer>\\n<script src=\\"js/main.js\\"></script>\\n</body>\\n</html>\\n"}	home	f	pages
