532	2026-04-07 23:40:21.111432+00	Text edit: home	page_text_edit	{"slug": "home", "file_path": "/home/claudeuser/agent/preview/index.html", "original_html": "<!DOCTYPE html>\\n\\n<html lang=\\"en\\">\\n<head>\\n<meta charset=\\"utf-8\\"/>\\n<meta content=\\"width=device-width, initial-scale=1.0\\" name=\\"viewport\\"/>\\n<title>Ridgecrest Designs — Luxury Design-Build | East Bay, California</title>\\n<meta content=\\"Ridgecrest Designs is a full-service luxury design-build firm serving Pleasanton, Walnut Creek, Danville, Lafayette, and the East Bay. Custom homes and high-end remodels.\\" name=\\"description\\"/>\\n<link href=\\"css/main.css\\" rel=\\"stylesheet\\"/>\\n<link href=\\"https://fonts.googleapis.com\\" rel=\\"preconnect\\"/>\\n<link crossorigin=\\"\\" href=\\"https://fonts.gstatic.com\\" rel=\\"preconnect\\"/>\\n<link href=\\"https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,500;1,300;1,400&amp;family=Jost:wght@300;400;500&amp;display=block\\" rel=\\"stylesheet\\"/>\\n<!-- ── SEO ──────────────────────────────────────────────────── -->\\n<link href=\\"https://www.ridgecrestdesigns.com/\\" rel=\\"canonical\\"/>\\n<meta content=\\"website\\" property=\\"og:type\\"/>\\n<meta content=\\"Ridgecrest Designs\\" property=\\"og:site_name\\"/>\\n<meta content=\\"Ridgecrest Designs — Luxury Design-Build | East Bay, California\\" property=\\"og:title\\"/>\\n<meta content=\\"Ridgecrest Designs is a full-service luxury design-build firm serving Pleasanton, Walnut Creek, Danville, Lafayette, and the East Bay. Custom homes and high-end remodels.\\" property=\\"og:description\\"/>\\n<meta content=\\"https://www.ridgecrestdesigns.com/\\" property=\\"og:url\\"/>\\n<meta content=\\"/assets/images/ff5b18_3c0cef18e48849089c5ed48614041900_mv2.png\\" property=\\"og:image\\"/>\\n<meta content=\\"summary_large_image\\" name=\\"twitter:card\\"/>\\n<meta content=\\"Ridgecrest Designs — Luxury Design-Build | East Bay, California\\" name=\\"twitter:ti